import Radio from '../radio/Radio'
import { RadioGroup } from '../radio/RadioGroup'
import { VisuallyHidden } from 'react-aria'
import { useState, useEffect } from 'react'

const AlignmentMatrix = (props) => {
  const [value, setValue] = useState(props.value ?? '')

  const options = [
    'top left',
    'top center',
    'top right',
    'center left',
    'center center',
    'center right',
    'bottom left',
    'bottom center',
    'bottom right',
  ]

  useEffect(() => props.onChange && props.onChange(value), [value])

  return (
    <div className='tf-alignment-matrix'>
      <RadioGroup {...props} onChange={setValue}>
        <div className='tf-alignment-matrix-container'>
          {options.map(option => (
            <Radio 
              key={ option } 
              id={ option } 
              value={ option }
            >
              <VisuallyHidden>
                { option }
              </VisuallyHidden>  
            </Radio>
          ))}
        </div>
      </RadioGroup>
    </div>
  )
}
export default AlignmentMatrix

import {
  useContext,
  useRef
} from 'react'

import { 
  useRadio,
  VisuallyHidden
} from 'react-aria' 

const ButtonOption = props => {

  const state = useContext(props.context)
  const ref = useRef(null)  

  const { inputProps } = useRadio(props, state, ref)

  let classes = 'tf-button-group-option'
  if( state.selectedValue === props.value ) {
    classes += ' tf-button-group-option-selected'
  } 

  return(
    <label className={ classes }>
      <VisuallyHidden>
        <input { ...inputProps } ref={ ref } />
      </VisuallyHidden>
      { props.children }
    </label>
  )
}

export default ButtonOption

